input.function:
() => {
  const topLevelComments = Array.from(document.querySelectorAll('tr.comtr')).filter(tr => {
    const indent = tr.querySelector('td.ind img');
    return indent && indent.width === 0;
  });

  const results = topLevelComments.map(tlc => {
    const id = tlc.id;
    const author = tlc.querySelector('.hnuser')?.innerText;
    let directReplies = 0;
    let current = tlc.nextElementSibling;
    while (current && current.classList.contains('comtr')) {
      const indent = current.querySelector('td.ind img');
      if (indent && indent.width === 40) { // Direct reply indentation in HN is 40px
        directReplies++;
      } else if (indent && indent.width === 0) {
        break; // Next top level comment
      }
      current = current.nextElementSibling;
    }
    return { author, directReplies };
  });

  results.sort((a, b) => b.directReplies - a.directReplies);
  return results[0];
}

